import React, { useEffect, useState } from 'react'
import { useNavigate } from 'react-router-dom';


const MyBookings = () => {

    const navigate = useNavigate();
    let data;
    const AuthenticationPage = async () => {
        try {
            const res = await fetch('/bookings', {
                method: "GET",
                headers: {
                    Accept: "application/json",
                    "Content-Type": "application/json",

                },
                credentials: "include"
            });

            data = await res.json();
            console.log(data);

            if (!res.status === 200) {
                const error = new Error(res.error);
                throw error;
            }
        }
        catch (err) {
            console.log(err);
            navigate('/login');
        }
    }

    const getBookingsPage = async () => {
        try {
            const res=await fetch('/showBookings',{
                method:"GET",
                headers: {
                    Accept: "application/json",
                    "Content-Type": "application/json",

                },
                
            })
        }
        catch (err) {
            console.log(err);
            navigate('/login');
        }
    }

    useEffect(() => {
        AuthenticationPage();
        getBookingsPage();
    }, []);

    // let {myBookings}=userData;

    return (
        <div className='flex justify-center items-center text-white text-3xl h-screen '>
            {/* {
          myBookings.length===0?<p>No Data</p>:<p>Data found</p>
        } */}
        </div>
    )
}

export default MyBookings
